import { createClient } from "@libsql/client";
import { drizzle } from "drizzle-orm/libsql";
import { eq } from "drizzle-orm";
import * as schema from "./src/db/schema";
import { cards } from "./src/db/schema";

const client = createClient({
  url: process.env.TURSO_DATABASE_URL!,
  authToken: process.env.TURSO_AUTH_TOKEN!,
});
const db = drizzle(client, { schema });

type StoryData = {
  story: string;
  keyIdea: string;
  quizQuestion: string;
  quizOptions: string; // JSON array
  quizAnswer: number;
};

const storiesByCardId: Record<string, StoryData> = {
  // ===== ATOMIC HABITS =====
  "card-book-1-1": {
    story: `Imagine two planes taking off from Los Angeles, both headed to New York City. One adjusts its heading by just 3.5 degrees south. At takeoff, the difference is invisible — the nose of the plane moves just a few feet. But over the course of a cross-country flight, that tiny shift lands you in Washington, D.C. instead of New York.\n\nThis is the power of 1% changes. James Clear discovered this principle after a devastating baseball injury left him struggling to rebuild his life. He didn't try to transform overnight. Instead, he focused on getting just a tiny bit better each day — in the gym, in class, in his sleep habits.\n\nThe math is startling: if you improve by 1% each day for a year, you'll be 37.78 times better by December 31st. But if you decline by 1% each day, you'll shrink down to nearly zero. The trajectory matters far more than any single moment.\n\nThink of an ice cube sitting in a room at 25 degrees. You raise the temperature one degree at a time. Nothing happens at 26, 27, 28... At 31 degrees, still just an ice cube. Then 32 degrees hits, and it begins to melt. One degree was no different from the others, but it was the one that unlocked a massive change. Your habits work the same way — results are delayed, but they're coming.`,
    keyIdea: `Small habits don't add up — they compound. A 1% improvement each day leads to being 37 times better in a year. The key insight is that breakthrough moments are often the result of many previous actions that built up potential. Be patient with your habits; the most powerful outcomes are delayed.`,
    quizQuestion: "What happens if you improve by 1% every day for an entire year?",
    quizOptions: JSON.stringify(["You become about 3.7 times better", "You become about 37 times better", "You become about 12 times better", "You become about 100 times better"]),
    quizAnswer: 1,
  },
  "card-book-1-2": {
    story: `A rowing coach at British Cycling named Dave Brailsford took over a team that had been mediocre for over a century. His strategy? He didn't focus on winning the Tour de France. Instead, he asked one question about everything: "How can we make this 1% better?"\n\nHe redesigned bike seats for comfort. He tested different massage gels for faster muscle recovery. He taught riders the best way to wash their hands to avoid illness. He even painted the inside of the team truck white so they could spot dust that might degrade bike performance.\n\nThese were systems, not goals. A goal is "win the Tour de France." A system is "optimize every tiny detail of cycling performance." The results? Within five years, British Cycling dominated the Tour de France and the Olympics.\n\nHere's the uncomfortable truth: winners and losers often have the same goals. Every Olympic athlete wants a gold medal. The difference isn't in what they want — it's in the systems they build to get there. Goals are about direction. Systems are about progress. You don't rise to the level of your goals; you fall to the level of your systems.`,
    keyIdea: `Goals set direction, but systems drive progress. Every Olympian has the same goal — gold. What separates winners is their daily systems. Instead of fixating on outcomes, build reliable processes. You don't rise to your goals; you fall to the level of your systems.`,
    quizQuestion: "According to Clear, what ultimately determines your success?",
    quizOptions: JSON.stringify(["The ambition of your goals", "The systems and processes you follow daily", "Your natural talent and intelligence", "How much you visualize success"]),
    quizAnswer: 1,
  },
  "card-book-1-3": {
    story: `There's a story about a man who quit smoking after years of failed attempts. What finally worked wasn't a patch, gum, or willpower challenge. During a visit to his doctor, she asked him, "Are you a smoker who's trying to quit, or a non-smoker who happens to have a craving right now?"\n\nThat reframe changed everything. He started saying "I'm not a smoker" instead of "I'm trying to quit smoking." One statement is about resisting who you are. The other is about becoming who you want to be.\n\nMost people start habit change by focusing on outcomes: "I want to lose 20 pounds." The next level is process: "I'm going to go to the gym four times a week." But the deepest and most lasting level is identity: "I am the type of person who moves their body every day."\n\nEvery action you take is a vote for the type of person you wish to become. No single vote is decisive, but as the votes accumulate, so does the evidence of your new identity. You don't have to be perfect — you just have to cast enough votes in the right direction.`,
    keyIdea: `True behavior change is identity change. Instead of focusing on what you want to achieve (outcomes), focus on who you want to become. Every small action is a "vote" for your desired identity. Ask yourself: "What would a healthy/productive/creative person do right now?"`,
    quizQuestion: "What is the most effective level of habit change, according to James Clear?",
    quizOptions: JSON.stringify(["Outcome-based: focusing on results", "Process-based: focusing on routines", "Identity-based: focusing on who you want to become", "Environment-based: focusing on your surroundings"]),
    quizAnswer: 2,
  },
  "card-book-1-4": {
    story: `Anne Thorndike, a doctor at Massachusetts General Hospital, wanted to improve eating habits in the hospital cafeteria — without telling anyone what to do. She didn't give lectures or post calorie counts. Instead, she rearranged the room.\n\nShe placed water bottles in baskets beside every food station, not just the drink refrigerators. She moved the salads to the front of the line. Over the next three months, soda sales dropped 11.4% while water sales jumped 25.8%. Nobody made a conscious decision to be healthier. The environment made the decision for them.\n\nThis is the First Law of Behavior Change: Make It Obvious. Your habits are triggered by cues, and the most powerful cues are built into your environment. The people with the best self-control are typically the ones who need to use it the least — because they've designed their world to minimize temptation.\n\nYou can apply this with "implementation intentions" — a specific plan for when and where you'll act. "I will meditate for one minute at 7 AM in my kitchen chair." The specificity eliminates the need for decision-making. When the time and place arrive, the behavior follows naturally.`,
    keyIdea: `The First Law: Make It Obvious. You don't need motivation if your environment does the work. Design your surroundings so good habits are the path of least resistance. Use implementation intentions — specific plans stating when, where, and how you'll perform a habit — to remove decision fatigue.`,
    quizQuestion: "In the hospital cafeteria study, what caused people to drink more water?",
    quizOptions: JSON.stringify(["Signs encouraging healthy choices", "Removing soda from the cafeteria", "Placing water bottles at every food station", "Increasing the price of soda"]),
    quizAnswer: 2,
  },
  "card-book-1-5": {
    story: `Neuroscientists have discovered something fascinating about dopamine: it's not primarily about pleasure — it's about anticipation. In experiments with monkeys, dopamine spikes not when they receive a reward, but when they predict one is coming. The wanting is more powerful than the having.\n\nThis is why social media is so addictive. Every time you open Instagram, you might see something amazing — or nothing at all. That unpredictability creates a dopamine loop of anticipation that keeps you scrolling.\n\nJames Clear suggests hijacking this mechanism for good through "temptation bundling." The formula is simple: link something you need to do with something you want to do. Want to binge Netflix? Only watch your favorite show while exercising on the stationary bike. Love gossip podcasts? Only listen while doing your accounting.\n\nA student named Ronan Byrne actually wired his stationary bike to his laptop so Netflix would only play while he was pedaling at a certain speed. When he stopped, the show paused. He went from hating exercise to looking forward to it — not because exercise changed, but because its association did.`,
    keyIdea: `The Second Law: Make It Attractive. Dopamine drives behavior through anticipation, not reward itself. Use "temptation bundling" — pair a habit you need to do with one you want to do. The more attractive you make a behavior, the more likely it becomes automatic.`,
    quizQuestion: "When does dopamine spike the most in the brain?",
    quizOptions: JSON.stringify(["When you receive a reward", "When you anticipate a reward", "When you finish a difficult task", "When you're in a state of flow"]),
    quizAnswer: 1,
  },
  "card-book-1-6": {
    story: `In 1970, a researcher named Jerry Uelsmann divided his photography class into two groups. The "quantity" group would be graded purely on the number of photos they submitted. The "quality" group only had to submit one photo, but it had to be perfect.\n\nAt the end of the semester, something surprising happened: all of the best photos came from the quantity group. While the quality group sat around theorizing about perfection, the quantity group was busy taking photos, learning from mistakes, experimenting with lighting and composition. Practice beat planning.\n\nThis is the core of the Third Law: Make It Easy. We often confuse motion with action. Motion is planning, strategizing, learning. Action is actually doing the thing that produces results. Motion feels productive without the risk of failure. But you can't plan your way to a six-pack.\n\nThe key insight is about friction. Every habit has a certain amount of friction associated with it. Want to exercise more? Sleep in your gym clothes. Want to eat healthier? Prep vegetables on Sunday. Want to waste less time on your phone? Leave it in another room. Each reduction in friction makes the good habit just a little more likely to happen.`,
    keyIdea: `The Third Law: Make It Easy. Don't optimize for the perfect plan — optimize for action. Reduce friction for good behaviors and increase friction for bad ones. The best habit is the one you actually do, not the one you plan perfectly.`,
    quizQuestion: "In the photography class experiment, which group produced the best photos?",
    quizOptions: JSON.stringify(["The quality group who focused on one perfect photo", "The quantity group who submitted as many as possible", "Both groups produced equally good work", "A control group that received no instructions"]),
    quizAnswer: 1,
  },
  "card-book-1-7": {
    story: `There's a behavioral economics concept called "time inconsistency" — the brain values immediate rewards more than future ones. Our ancestors didn't have 401(k)s. They needed food now, shelter now, safety now. Evolution wired us for immediate returns.\n\nThis creates a problem: the consequences of good habits are delayed, while the consequences of bad ones are immediate. Eating a donut feels good right now. The weight gain shows up months later. Going to the gym feels hard right now. The fit body appears months later. The reward timeline is inverted.\n\nJames Clear's solution is the Fourth Law: Make It Satisfying. You need to add an immediate reward to good habits. One couple wanted to eat out less and cook more, so every time they skipped a restaurant meal, they transferred $50 to a vacation savings account. The immediate "reward" of watching their trip fund grow made cooking at home feel satisfying.\n\nThe cardinal rule of behavior change: what is immediately rewarded is repeated. What is immediately punished is avoided. You live in a delayed-return environment, but your brain still operates on immediate-return software. Bridge the gap by making good habits feel good right now.`,
    keyIdea: `The Fourth Law: Make It Satisfying. Your brain prioritizes immediate rewards over delayed ones — that's evolution. To stick with good habits, add an immediate reward. Track your habits, celebrate small wins, and make the experience of doing the right thing feel good in the moment.`,
    quizQuestion: "Why is it hard to maintain good habits, according to behavioral economics?",
    quizOptions: JSON.stringify(["People lack willpower and discipline", "Good habits require too much time investment", "Good habit rewards are delayed while bad habit rewards are immediate", "Society doesn't support good habits"]),
    quizAnswer: 2,
  },
  "card-book-1-8": {
    story: `In the Vietnam War, something alarming happened: about 20% of U.S. soldiers became addicted to heroin while deployed. Government officials braced for a wave of addiction when the troops came home. But something remarkable occurred — 95% of the addicted soldiers simply stopped using when they returned.\n\nThis wasn't willpower. It was environment. In Vietnam, heroin was everywhere — easy to access, socially normalized, and a way to cope with terror. Back home, the triggers disappeared. Different friends, different routines, different surroundings.\n\nContrast this with patients who become addicted to painkillers in hospitals. They return to the same home, same stressors, same environment. Their relapse rate? About 90%. Same drug, different environmental story.\n\nThis is why "just say no" fails. Your environment is the invisible hand shaping your behavior more than your conscious will ever could. Want to read more? Put a book on every surface in your house. Want to drink less? Don't keep alcohol at home. Want to practice guitar? Leave it in the middle of the living room. The most disciplined people aren't born that way — they've engineered their environment to make good choices the default.`,
    keyIdea: `Your environment shapes your behavior more than willpower ever will. The Vietnam heroin study proves it: change the context, change the habit. Design your spaces to make good behaviors obvious and bad behaviors invisible. Discipline is largely a product of environment design.`,
    quizQuestion: "What happened to most Vietnam soldiers addicted to heroin when they returned home?",
    quizOptions: JSON.stringify(["They required years of rehabilitation", "About 95% simply stopped using without treatment", "Most switched to different substances", "Government programs cured their addictions"]),
    quizAnswer: 1,
  },
  "card-book-1-9": {
    story: `A yoga instructor noticed something about her new students. The ones who committed to a 90-minute practice three times a week almost always quit within a month. But the ones who started with just two minutes of stretching each morning? They were still practicing years later.\n\nJames Clear formalized this observation into the Two-Minute Rule: when you start a new habit, it should take less than two minutes. Want to read before bed? Start by reading one page. Want to run every morning? Start by putting on your running shoes. Want to meditate? Start by sitting quietly for 120 seconds.\n\nIt sounds absurdly simple, almost insulting. But the point isn't the two minutes — it's the identity you're building. Every day you read one page, you cast a vote for "I am a reader." Every day you put on your running shoes, you cast a vote for "I am a runner." The habit of showing up is more important than the habit of performing.\n\nA reader once told Clear, "I feel silly going to the gym for just five minutes." Clear responded: "You're not trying to get a workout in five minutes. You're trying to become the type of person who doesn't miss workouts." Once the identity sticks, scaling up happens naturally.`,
    keyIdea: `The Two-Minute Rule: scale any habit down to something that takes less than two minutes. The goal isn't the two minutes themselves — it's building the identity of someone who shows up consistently. Master the art of showing up before you optimize the performance.`,
    quizQuestion: "What is the real purpose of the Two-Minute Rule?",
    quizOptions: JSON.stringify(["To get meaningful results in just two minutes", "To build the identity of someone who shows up consistently", "To save time on unimportant habits", "To test whether a habit is worth pursuing"]),
    quizAnswer: 1,
  },
  "card-book-1-10": {
    story: `In 1993, a stockbroker named Trent Dyrsmid got a new job. He was young, inexperienced, and working at a firm in a small Canadian city. Yet within 18 months, he was bringing in $5 million in revenue and landed a job at one of the biggest firms in the country.\n\nHis secret? Two jars and 120 paper clips. Each morning, he'd start with 120 paper clips in one jar and an empty jar beside it. Every time he made a sales call, he'd move one clip to the second jar. He wouldn't stop until all 120 had been transferred.\n\nThis is habit tracking in its purest form. The visual progress — watching the clips accumulate — created immediate satisfaction. The streak itself became the reward. Research shows that people who track their habits are more likely to stick with them, and the simple act of measurement creates awareness that changes behavior.\n\nThere's a powerful secondary effect: never break the chain twice. Missing one day is an accident. Missing two days is the start of a new pattern. The first mistake is never the one that ruins you — it's the spiral of repeated mistakes that follows. Bad days happen. The key is to show up on the bad days, even if you do less than usual. Lost days hurt more than successful days help.`,
    keyIdea: `Habit tracking provides the immediate satisfaction that good habits otherwise lack. The visual proof of progress — whether paper clips, X's on a calendar, or an app — becomes its own reward. And remember: never miss twice. One bad day is fine; a streak of misses creates a new (bad) habit.`,
    quizQuestion: "According to the paper clip strategy, what made Trent Dyrsmid successful?",
    quizOptions: JSON.stringify(["His natural talent for sales", "Visual tracking that made each action feel rewarding", "Working longer hours than his colleagues", "Setting ambitious revenue goals"]),
    quizAnswer: 1,
  },
  // ===== DEEP WORK =====
  "card-book-2-1": {
    story: `Carl Jung, one of the most influential thinkers of the 20th century, had a problem. In the 1920s, he was engaged in a fierce intellectual battle with Sigmund Freud, and he needed to produce groundbreaking work to establish his own school of psychology. But the demands of his Zurich psychiatric practice — patients, lectures, correspondence — consumed his days.\n\nSo Jung did something radical. He built a stone tower in the village of Bollingen, on the shore of Lake Zurich. No electricity. No phone. Just stone walls and silence. He would retreat there regularly to think, write, and develop his most complex theories. The tower wasn't a vacation — it was a productivity weapon.\n\nThis is deep work: professional activities performed in a state of distraction-free concentration that push your cognitive capabilities to their limit. It's what produced Jung's theories, what allowed J.K. Rowling to finish Harry Potter (she checked into a hotel suite to escape distractions), and what allows programmers to write elegant code.\n\nDeep work is cognitively demanding. It's the mental equivalent of heavy lifting. But it's also where value is created — the insights, the breakthroughs, the work that can't be replicated by a machine or an intern.`,
    keyIdea: `Deep work is rare, focused concentration that produces your most valuable output. It requires eliminating distractions entirely — not just minimizing them. History's greatest thinkers (Jung, Darwin, Rowling) all built structures and rituals specifically to protect their deep work time.`,
    quizQuestion: "Why did Carl Jung build a stone tower in Bollingen?",
    quizOptions: JSON.stringify(["As a vacation retreat from Zurich", "To create a distraction-free environment for deep thinking", "To impress his patients and colleagues", "Because he enjoyed architecture as a hobby"]),
    quizAnswer: 1,
  },
  "card-book-2-2": {
    story: `Meet Nate. He's a marketing manager at a mid-size tech company. His typical day: arrives at 9 AM, immediately checks email (47 new messages). Responds to 12 of them. Slack pings — a colleague needs feedback on a deck. Quick meeting at 10. Back to email. Lunch. Afternoon: three more meetings, each 30 minutes. Between meetings, he fills the gaps with more email, more Slack, more "quick tasks."\n\nBy 5 PM, Nate is exhausted. He feels busy. But what did he actually produce? Nothing that required real thinking. No strategy document, no creative campaign, no deep analysis. Just a day of reacting to other people's priorities.\n\nThis is the shallow work trap. Shallow work feels productive because it's constant. There's always another email to answer, another message to send, another small request to fulfill. But these tasks are non-cognitively demanding and easy to replicate. An intern could do most of them. An AI definitely could.\n\nThe insidious part is that organizations often reward shallow work. Responding quickly to emails signals "dedication." Being in meetings signals "collaboration." But none of it creates the kind of value that advances careers or moves businesses forward. The busiest people are often producing the least valuable work.`,
    keyIdea: `Shallow work — email, meetings, quick tasks — feels productive but creates little lasting value. It's the default mode of most knowledge workers because it's easy and socially rewarded. Breaking free requires deliberately protecting time for deeper, more cognitively demanding work.`,
    quizQuestion: "Why is shallow work so common in modern workplaces?",
    quizOptions: JSON.stringify(["It requires the most skill and training", "It feels productive and is socially rewarded by organizations", "It produces the most valuable output", "Managers specifically assign it to top performers"]),
    quizAnswer: 1,
  },
  "card-book-2-3": {
    story: `In the early 2010s, economists Erik Brynjolfsson and Andrew McAfee began studying which workers thrive in the new economy. They identified three groups: those who work with intelligent machines, superstars in their field, and those with access to capital. The common thread for the first two? The ability to do deep work.\n\nConsider Nate Silver, the statistician who famously predicted the outcomes of 49 out of 50 states in the 2012 U.S. election. His advantage wasn't just mathematical talent — thousands of statisticians share that. His edge was the ability to spend months in deep concentration, building and refining complex models while others got distracted by punditry and hot takes.\n\nAs AI and automation advance, the work that machines can't replicate — creative problem-solving, complex strategy, novel insights — requires exactly the kind of sustained concentration that deep work provides. Yet at the same time, the open-office movement, instant messaging, and the cult of responsiveness are systematically destroying our capacity for deep work.\n\nThis creates a massive economic opportunity. Deep work is becoming both rarer and more valuable simultaneously. Those who cultivate this skill — who can regularly produce at an elite level — will thrive. Everyone else will be competing for scraps of shallow work that machines will eventually handle better.`,
    keyIdea: `Deep work is simultaneously becoming rarer (due to distractions, open offices, and always-on culture) and more valuable (as routine cognitive work gets automated). This paradox means the few who master deep concentration will have an enormous competitive advantage in the modern economy.`,
    quizQuestion: "Why is deep work becoming more valuable in today's economy?",
    quizOptions: JSON.stringify(["Because companies are paying more for long work hours", "Because routine cognitive work is being automated, making deep thinking the remaining human edge", "Because deep workers are naturally more intelligent", "Because universities now require deep work skills for admission"]),
    quizAnswer: 1,
  },
  "card-book-2-4": {
    story: `Donald Knuth is one of the most important computer scientists alive. He created TeX (the typesetting system used in nearly every academic paper), wrote "The Art of Computer Programming," and has won basically every award in his field. He also doesn't use email.\n\nSince 1990, Knuth has had no email address. If you want to reach him, you write a letter. He reads them in batches. His reasoning: "Email is a wonderful thing for people whose role in life is to be on top of things. But not for me; my role is to be on the bottom of things. What I do takes long hours of studying and uninterruptible concentration."\n\nThis is the monastic philosophy of deep work — the most extreme approach. You essentially eliminate shallow obligations from your life. It's not for everyone. It works best for people with a singular, well-defined professional mission that they pursue with maximum dedication.\n\nNeal Stephenson, the science fiction author, takes a similar approach. His website essentially says: don't contact me. He can either write good novels or answer your email, but not both. The monastic philosophy requires accepting a trade-off that most people aren't willing to make — but for those who do, the output can be extraordinary.`,
    keyIdea: `The monastic philosophy eliminates or radically minimizes shallow obligations to maximize deep work. It's extreme but effective for those with a singular professional mission. The key trade-off: you become unreachable to most people, but your output becomes extraordinary.`,
    quizQuestion: "Why has Donald Knuth refused to use email since 1990?",
    quizOptions: JSON.stringify(["He's uncomfortable with technology", "His work requires uninterruptible concentration that email destroys", "He prefers social media for communication", "His university banned personal email use"]),
    quizAnswer: 1,
  },
  "card-book-2-5": {
    story: `Jerry Seinfeld was once asked by a young comedian for advice on how to be funnier. His answer had nothing to do with joke structure or timing. He said: get a big wall calendar with a whole year on one page. Every day you write new jokes, put a big red X on that day. After a few days, you'll have a chain. Your only job now is to not break the chain.\n\nThis is the rhythmic philosophy of deep work — arguably the most practical approach for people with regular jobs. Instead of trying to find sporadic blocks of intense focus, you build deep work into a daily rhythm. Same time, same place, same duration. No decision-making required.\n\nA professor named Brian Chappell used this method to finish his dissertation while holding a full-time job and raising a family. Every morning, 5:30 to 7:30 AM, he wrote. No exceptions. He didn't have to decide each morning whether he felt like working on his dissertation. The schedule decided for him.\n\nThe power of the rhythmic approach is that it removes the biggest barrier to deep work: starting. When deep work is a habit tied to a specific time slot, you don't need motivation or inspiration. You just need to show up. And showing up, day after day, accumulates into something remarkable.`,
    keyIdea: `The rhythmic philosophy transforms deep work into a simple daily habit — same time, same place, no decisions. It's the most practical approach for people with busy schedules. By removing the decision of "when should I do deep work?", you eliminate the biggest barrier: starting.`,
    quizQuestion: "What is the core principle behind Jerry Seinfeld's 'chain method'?",
    quizOptions: JSON.stringify(["Focus on quality over quantity", "Never break a daily streak of consistent practice", "Write jokes only when inspiration strikes", "Compete with other comedians daily"]),
    quizAnswer: 1,
  },
  "card-book-2-6": {
    story: `Sophie Leroy, a business professor at the University of Minnesota, ran an experiment that revealed something troubling about how we work. She gave participants a set of word puzzles to solve, then interrupted them midway to switch to a new task. Even after switching, participants' brains kept processing the unfinished puzzles — a phenomenon she called "attention residue."\n\nThe residue was especially thick when the first task was unfinished or had no clear stopping point. It's like having 20 browser tabs open in your brain — each one consuming a tiny bit of processing power, even though you're only looking at one.\n\nThis explains why multitasking is so devastating. When you check your email between deep work sessions, your mind doesn't cleanly switch. A residue of "I need to respond to that client" or "what did my boss mean by that message?" lingers, degrading your cognitive performance on the task at hand.\n\nThe practical implication is clear: batching is everything. Don't check email between tasks. Don't glance at your phone during a work session. Every context switch leaves a residue that takes 15-25 minutes to fully clear. A single "quick peek" at your inbox can derail 30 minutes of productive thinking.`,
    keyIdea: `When you switch between tasks, your attention doesn't follow cleanly — a "residue" from the previous task lingers and degrades performance. Every quick email check or phone glance costs 15-25 minutes of reduced cognitive capacity. Batch your work and eliminate mid-session switching.`,
    quizQuestion: "What is 'attention residue' as described by Sophie Leroy?",
    quizOptions: JSON.stringify(["The tiredness you feel after a long day of work", "Leftover cognitive processing from a previous task that impairs the current one", "The ability to remember details from earlier tasks", "A technique for improving multitasking ability"]),
    quizAnswer: 1,
  },
  "card-book-2-7": {
    story: `Here's a counterintuitive experiment to try: schedule your internet time instead of your offline time. Most people think of the internet as their default state and focus as something they dip into occasionally. Cal Newport argues for the reverse.\n\nImagine you decide: "I will use the internet at 10 AM, 12 PM, and 3 PM for 15 minutes each." Outside those windows, you're offline. No email, no social media, no news, no "quick Google searches." At first, this feels excruciating. You'll reach for your phone. You'll feel the urge to "just check one thing." Good. That discomfort is the feeling of your brain rewiring.\n\nThe problem isn't that the internet is bad — it's that constant connectivity trains your brain to crave novel stimuli. Like a drug, the more you feed the craving, the stronger it gets. Your brain literally loses the ability to tolerate boredom, which is the foundation of sustained concentration.\n\nNewport points to a key study: people who were asked to sit alone in a room with nothing to do for 15 minutes found it so unbearable that many chose to give themselves electric shocks rather than be bored. If your brain can't handle boredom for 15 minutes, how can it handle the hour of sustained focus needed for deep work?`,
    keyIdea: `Don't take breaks from distraction — take breaks from focus. Schedule specific internet time and stay offline otherwise. The goal is to retrain your brain to tolerate boredom, which is the foundation of deep concentration. Constant connectivity destroys your capacity for sustained thought.`,
    quizQuestion: "What does Cal Newport suggest about internet usage?",
    quizOptions: JSON.stringify(["Use the internet only on weekends", "Schedule specific internet times and stay offline otherwise", "Delete all social media accounts permanently", "Use internet blocking apps during work hours only"]),
    quizAnswer: 1,
  },
  "card-book-2-8": {
    story: `Cal Newport proposes a radical experiment: try to finish all your work by 5:30 PM. Not because you should work less, but because the constraint forces you to be ruthless about what matters.\n\nWhen your workday has a hard endpoint, you can't say yes to every meeting. You can't spend 90 minutes on email each morning. You have to actively decide: "Is this shallow or deep? Does this deserve my limited time?" Newport calls this "draining the shallows."\n\nHe suggests a concrete exercise: schedule every minute of your workday in advance. Not to become rigid, but to become intentional. When you see your entire day laid out, shallow work becomes impossible to hide. That two-hour meeting with no clear agenda? Suddenly obvious it's a waste. Those 45 minutes of "catching up on email"? Clearly could be compressed to 15.\n\nThen, quantify the depth of every activity. Ask: "How many months of training would it take to replace me on this task?" If the answer is less than a few months, it's shallow. Schedule it into tight blocks and protect the remaining time for deep work. Most knowledge workers discover that 30-50% of their day is consumed by tasks that a smart college graduate could handle.`,
    keyIdea: `Set a hard stop time for your workday and schedule every minute intentionally. This constraint forces you to eliminate low-value shallow work. Quantify depth by asking: "How long would it take to train someone to do this?" If the answer is short, it's shallow — minimize it ruthlessly.`,
    quizQuestion: "How does Newport suggest you evaluate whether a task is 'shallow'?",
    quizOptions: JSON.stringify(["Check if the task can be done remotely", "Ask how many months it would take to train a replacement for that task", "Measure how many calories the task burns", "Determine if the task requires a college degree"]),
    quizAnswer: 1,
  },
  "card-book-2-9": {
    story: `Great chess players don't just practice more than average ones — they practice differently. Researchers studying expert performance found that what separates grandmasters from club players isn't hours logged, but the intensity of those hours. Grandmasters spend their practice time on the most cognitively demanding activities: studying difficult positions, analyzing their mistakes, solving complex puzzles.\n\nCal Newport draws a parallel to deep work: it's a skill that must be trained like a muscle. You can't expect to sit down and concentrate for four hours if your longest stretch of focus this month was 20 minutes. Start where you are, and build up.\n\nThe key is building rituals that minimize willpower. Where will you work? For how long? What's the rule about internet during that time? What food or drink will you have? These aren't trivial details — they're the scaffolding that supports concentrated effort.\n\nNewport describes how Charles Darwin built a "thinking path" at his home — a gravel walkway he'd pace while contemplating his theories. The walk itself was the ritual. It signaled to his brain: it's time to think deeply now. Your ritual might be a specific desk, a certain playlist, a cup of a particular tea. The specific elements matter less than their consistency.`,
    keyIdea: `Deep work is a skill that requires training, not just willpower. Build rituals and routines that signal to your brain "it's time to focus." Minimize decisions about when, where, and how you'll do deep work. Like an athlete's pre-game routine, your deep work ritual should be automatic.`,
    quizQuestion: "What separates chess grandmasters from average players, according to performance research?",
    quizOptions: JSON.stringify(["They spend more total hours playing chess", "They focus practice on the most cognitively demanding activities", "They started learning chess at a younger age", "They have higher natural intelligence"]),
    quizAnswer: 1,
  },
  "card-book-2-10": {
    story: `At the end of each workday, Cal Newport performs a specific ritual. He reviews his task list, checks his calendar for the next day, and makes a rough plan for tomorrow. Then he says a specific phrase: "Shutdown complete." After that, he does not check email, does not think about work problems, does not "just quickly" review a document.\n\nThis isn't laziness — it's neuroscience. Research on "unconscious thought theory" suggests that for complex decisions and problems, your unconscious mind continues processing information even after you stop actively thinking about it. But this only works if you actually stop. Half-attention — worrying about work while watching TV — gives you neither the benefits of rest nor the benefits of focus.\n\nThere's also the simple matter of finite resources. Attention is like a battery. Deep work drains it rapidly. Studies suggest most people have about four hours of deep work capacity per day. After that, you're running on fumes. The shutdown ritual ensures you don't waste your evening on low-quality "residual" work that accomplishes nothing but depletes tomorrow's cognitive reserves.\n\nThe phrase "shutdown complete" might sound silly, but it serves as a cognitive anchor — a clear signal to your brain that work mode is over. Without it, open loops and unfinished tasks keep your mind spinning long into the evening.`,
    keyIdea: `A shutdown ritual at day's end — reviewing tasks, planning tomorrow, then completely disconnecting — is essential for deep work sustainability. Your unconscious mind processes complex problems during rest, but only if you truly disengage. Most people have ~4 hours of deep work capacity daily; protect it.`,
    quizQuestion: "Why is a shutdown ritual important for deep work?",
    quizOptions: JSON.stringify(["It helps you work longer hours the next day", "It allows your unconscious mind to process problems and recharges cognitive reserves", "It signals to your employer that you've finished working", "It prevents you from forgetting important tasks"]),
    quizAnswer: 1,
  },
  // ===== THINKING, FAST AND SLOW =====
  "card-book-3-1": {
    story: `You're walking down a dark alley at night. A shadow moves. Before you can even form a conscious thought, your heart rate spikes, your muscles tense, and you're ready to run. A second later, you realize it was just a cat. But for that instant, your brain made a snap judgment at incredible speed — and it might have saved your life.\n\nThis is System 1: your brain's fast, automatic, always-on processor. It recognizes faces, completes phrases ("bread and..."), detects anger in a voice, and drives your car on an empty road. It operates with zero conscious effort. You don't decide to flinch at a loud noise — System 1 does it for you.\n\nSystem 1 is extraordinarily powerful. It's been refined by millions of years of evolution to handle the decisions that matter most for survival. It can read social situations, detect threats, and navigate familiar environments without breaking a sweat.\n\nBut here's the catch: System 1 can't be turned off, and it's confidently wrong more often than you'd think. It substitutes difficult questions with easier ones ("Is this investment risky?" becomes "Do I feel good about this?"). It sees patterns where none exist. It jumps to conclusions based on tiny amounts of evidence. Understanding System 1 is the first step to thinking more clearly.`,
    keyIdea: `System 1 is your brain's fast, automatic thinking engine — brilliant for survival, but prone to systematic errors. It operates without conscious effort, making snap judgments based on emotions, pattern recognition, and mental shortcuts. Knowing its strengths and blind spots is the key to better decisions.`,
    quizQuestion: "What is a key limitation of System 1 thinking?",
    quizOptions: JSON.stringify(["It's too slow for important decisions", "It substitutes hard questions with easier ones and jumps to conclusions", "It only works during high-stress situations", "It requires significant conscious effort to activate"]),
    quizAnswer: 1,
  },
  "card-book-3-2": {
    story: `Try this: what is 17 × 24? Unless you're a mental math prodigy, you just felt something shift in your brain. Your pupils dilated slightly. Your heart rate increased. You might have looked away from the screen. That shift is System 2 activating — your brain's slow, deliberate, effortful thinking mode.\n\nSystem 2 is what you use when you parallel park in a tight space, fill out a tax form, compare the features of two washing machines, or check the logic of an argument. It requires attention, and attention is a limited resource. You can't multiply 17 × 24 while simultaneously composing a text message — System 2 can only handle one demanding task at a time.\n\nHere's the crucial insight: System 2 is lazy. It takes energy to activate. Given any opportunity, your brain will default to System 1's quick-and-dirty answers rather than engaging System 2's careful analysis. This is why you believe misleading statistics, fall for marketing tricks, and make impulsive purchases — System 2 was off duty.\n\nKahneman describes System 2 as having the subjective feeling of "agency, choice, and concentration." When you feel like "you" are deciding something, that's System 2. But most of your day — perhaps 95% — is run by System 1. The illusion that you're always in the driver's seat is one of the most persistent myths about human cognition.`,
    keyIdea: `System 2 is your deliberate, analytical mind — powerful but lazy and easily depleted. It can only handle one demanding task at a time and defaults to letting System 1 run the show. Most of your decisions are made automatically; the feeling of conscious choice is less common than you think.`,
    quizQuestion: "Why does System 2 often fail to catch errors in our thinking?",
    quizOptions: JSON.stringify(["It's less intelligent than System 1", "It's inherently lazy and requires energy to activate", "It only works during morning hours", "It was designed for physical tasks, not mental ones"]),
    quizAnswer: 1,
  },
  "card-book-3-3": {
    story: `In a famous experiment, Kahneman and Tversky spun a wheel of fortune in front of United Nations delegates. The wheel was rigged to land on either 10 or 65. Then they asked: "Is the percentage of African countries in the UN higher or lower than this number?" And then: "What is your best estimate?"\n\nDelegates who saw 65 on the wheel estimated an average of 45%. Those who saw 10 estimated 25%. These were experienced diplomats — people who should have known the actual number. Yet a completely random spin of a wheel shifted their answers by 20 percentage points.\n\nThis is the anchoring effect, and it's everywhere. Real estate agents shown a high listing price estimate home values higher than those shown a low one — even though they insist the listing price didn't influence them. Salary negotiations are dominated by whoever states a number first. Store prices ending in ".99" work because they anchor you to the lower dollar amount.\n\nWhat makes anchoring so insidious is that knowing about it doesn't make you immune. Even Kahneman himself admits he falls for anchors. System 1 automatically adjusts from whatever number it's given, and that adjustment is almost always insufficient. The anchor sticks like glue.`,
    keyIdea: `The anchoring effect means your estimates are heavily influenced by whatever number you encounter first — even if it's completely random. This affects negotiations, purchases, and judgments of all kinds. Knowing about anchoring helps, but doesn't make you immune. In negotiations, always try to set the first number.`,
    quizQuestion: "In the UN wheel experiment, what happened to delegates' estimates?",
    quizOptions: JSON.stringify(["They were accurate regardless of the wheel number", "Their estimates shifted dramatically based on the random wheel number", "Only inexperienced delegates were affected", "The wheel number only affected estimates by 1-2 percentage points"]),
    quizAnswer: 1,
  },
  "card-book-3-4": {
    story: `Imagine two scenarios. In Scenario A, you receive $1,000 and then must choose between: a guaranteed $500 more, or a 50% chance to get $1,000 more. In Scenario B, you receive $2,000 and then must choose between: a guaranteed loss of $500, or a 50% chance of losing $1,000.\n\nMathematically, these scenarios are identical. Both offer a choice between a sure $1,500 or a coin-flip between $1,000 and $2,000. But most people choose the sure gain in Scenario A and the gamble in Scenario B. We're risk-averse with gains and risk-seeking with losses.\n\nThis is loss aversion — perhaps Kahneman and Tversky's most famous discovery. The pain of losing $100 is roughly twice as intense as the pleasure of gaining $100. Evolution explains why: for our ancestors, a loss (losing food, shelter, a mate) could mean death, while a gain was just a nice bonus. The asymmetry was survival-critical.\n\nLoss aversion explains so much: why people hold losing stocks too long (selling would "realize" the loss), why negotiators refuse fair deals that feel like concessions, why companies hesitate to discontinue failing products, and why "limited time offers" work so well — they frame not-buying as a loss.`,
    keyIdea: `Losses hurt roughly twice as much as equivalent gains feel good — a deep evolutionary bias called loss aversion. This distorts decisions everywhere: investing, negotiating, shopping, relationships. We gamble to avoid losses but play it safe with gains. Awareness of this asymmetry is crucial for rational decision-making.`,
    quizQuestion: "How does loss aversion affect investment behavior?",
    quizOptions: JSON.stringify(["Investors sell winning stocks too quickly", "Investors hold losing stocks too long to avoid 'realizing' the loss", "Investors only buy low-risk bonds", "Investors ignore stock prices entirely"]),
    quizAnswer: 1,
  },
  "card-book-3-5": {
    story: `After the September 11 attacks, millions of Americans stopped flying and drove instead. In the year following 9/11, an estimated 1,600 additional people died in car accidents — roughly six times the number who died in the planes that day. The roads were far more dangerous than the skies, but fear of flying felt rational because plane crashes are vivid, dramatic, and memorable.\n\nThis is the availability heuristic: we estimate how common something is based on how easily examples come to mind. Shark attacks feel more likely than they are because they make spectacular news. Lottery winners feel common because we see them on TV. Quiet, statistical killers — heart disease, diabetes, car accidents — feel less threatening because they lack dramatic imagery.\n\nMedia amplifies the availability heuristic to an extreme degree. A single plane crash gets weeks of coverage. The 100+ people who die in car accidents every single day in the U.S. get almost none. Your perception of risk becomes a funhouse mirror reflection of actual risk.\n\nKahneman suggests a corrective: whenever you're estimating risk or frequency, ask yourself, "Am I thinking of examples because they're common, or because they're memorable?" Then look up the actual statistics. You'll be surprised how often your gut feeling is wildly off.`,
    keyIdea: `We judge how common or dangerous something is by how easily we can recall examples — the availability heuristic. Dramatic, vivid events (plane crashes, shark attacks) feel more likely than mundane, statistical dangers (car accidents, heart disease). Always check base rates before trusting your gut on risk.`,
    quizQuestion: "Why did more people die on roads after 9/11?",
    quizOptions: JSON.stringify(["Road conditions worsened after the attacks", "People drove more recklessly due to stress", "Millions avoided flying due to vivid fear, choosing statistically more dangerous driving", "Airports directed travelers to drive instead"]),
    quizAnswer: 2,
  },
  "card-book-3-6": {
    story: `A disease outbreak hits your town. 600 people will die without treatment. The government offers two programs:\n\nVersion 1: "Program A will save 200 people. Program B has a 1/3 chance of saving 600 people and a 2/3 chance of saving nobody." Most people pick A — the sure save.\n\nNow the same scenario, different wording:\n\nVersion 2: "Program C means 400 people will die. Program D has a 1/3 chance that nobody dies and a 2/3 chance that 600 die." Now most people pick D — the gamble.\n\nBut A and C are identical (200 saved = 400 die). B and D are identical. Only the frame changed. "Save 200" and "400 will die" describe the exact same outcome, yet they trigger completely different emotional responses and decisions.\n\nFraming effects reveal that we don't evaluate options objectively — we react to the way they're presented. Doctors make different treatment recommendations depending on whether outcomes are framed as survival rates or mortality rates. Consumers buy more "95% fat-free" yogurt than "5% fat" yogurt. The frame is the message.`,
    keyIdea: `Framing — how information is presented — dramatically changes decisions, even when the underlying facts are identical. "Save 200 lives" and "400 will die" describe the same outcome but trigger opposite choices. Always reframe important decisions both ways (gain and loss) before deciding.`,
    quizQuestion: "What do framing effects demonstrate about human decision-making?",
    quizOptions: JSON.stringify(["People always choose the mathematically optimal option", "The way information is presented changes decisions even when facts are identical", "Framing only affects uneducated decision-makers", "People are immune to framing when making important decisions"]),
    quizAnswer: 1,
  },
  "card-book-3-7": {
    story: `Here's a cruel experiment that reveals something profound about how we experience life. Patients undergoing a colonoscopy (an unpleasant medical procedure) were randomly assigned to one of two groups. Group A had a standard procedure. Group B had the same procedure but with an extra period at the end where the scope was left in place (uncomfortable, but less painful than the active examination).\n\nGroup B's procedure was objectively worse — it lasted longer and included everything Group A experienced plus more. Yet Group B rated the experience as significantly less unpleasant. Why? Because the ending was milder. Their memories were shaped by the peak-end rule.\n\nWe don't remember experiences as the sum of every moment. Instead, we remember the peak (most intense point) and the end. A vacation with a terrible last day is remembered as worse than a shorter vacation that ended on a high note — even if the overall pleasure was identical.\n\nThis has profound implications. Restaurants know to make dessert spectacular. Speakers know to save their best story for the close. Disney engineers the exit experience at their parks. You can even apply it to your own life: end your workday with something enjoyable, end conversations on a warm note, and end vacations with a simple, pleasant day rather than a stressful travel day.`,
    keyIdea: `We judge experiences by their most intense moment (peak) and how they end — not by their average or duration. A painful procedure with a mild ending is remembered as less unpleasant than a shorter one with a harsh ending. Design your experiences (and others') with memorable peaks and strong endings.`,
    quizQuestion: "Why did patients rate the longer colonoscopy as less unpleasant?",
    quizOptions: JSON.stringify(["The longer procedure was actually less painful throughout", "Their doctors provided better pain medication", "The procedure ended with a milder period, creating a better 'end' memory", "They were distracted by conversation during the extra time"]),
    quizAnswer: 2,
  },
  "card-book-3-8": {
    story: `A bat and a ball cost $1.10 together. The bat costs $1.00 more than the ball. How much does the ball cost?\n\nIf you thought "10 cents," you're in good company — over 50% of students at Harvard, MIT, and Princeton give that answer. But it's wrong. If the ball costs 10 cents and the bat costs $1.00 more, the bat costs $1.10, making the total $1.20. The correct answer is 5 cents.\n\nThis is WYSIATI in action: What You See Is All There Is. System 1 took the available information, constructed the most coherent story it could ("$1.10 minus $1.00 = 10 cents"), and delivered it with confidence. It didn't check whether the answer actually satisfied the constraints. It didn't flag uncertainty. It just... answered.\n\nKahneman argues this is how System 1 always operates. It builds the best possible narrative from available data, with no consideration for what data might be missing. This is why first impressions are so powerful, why we judge books by covers, and why we're confident in opinions formed from a single news headline. The less information you have, the easier it is to construct a coherent story — and ironically, the more confident you feel.`,
    keyIdea: `WYSIATI (What You See Is All There Is): your brain builds confident narratives from limited information without considering what's missing. Less data paradoxically means more confidence, because it's easier to create a coherent story. Always ask: "What don't I know?" before trusting your judgment.`,
    quizQuestion: "Why does having less information sometimes increase confidence?",
    quizOptions: JSON.stringify(["Because less information means fewer contradictions, making it easier to build a coherent story", "Because ignorance naturally leads to overconfidence", "Because System 2 works better with less data", "Because people prefer simple explanations regardless of accuracy"]),
    quizAnswer: 0,
  },
  "card-book-3-9": {
    story: `A flight instructor once told Daniel Kahneman: "Praise doesn't work. When I praise a cadet for a smooth landing, the next one is always worse. When I scream at them for a rough landing, the next one is always better. Punishment works; praise doesn't."\n\nKahneman realized the instructor was falling for one of the most widespread illusions in human reasoning. The explanation wasn't that punishment works — it was regression to the mean. An exceptionally smooth landing is, by definition, above the pilot's average. The next landing is statistically likely to be closer to average — i.e., worse — regardless of what anyone says. Similarly, an exceptionally rough landing is below average, so the next one will likely improve naturally.\n\nThis illusion is everywhere. A sports team has a stellar season, so the manager gets extended. The next season is mediocre, and the "sophomore slump" is blamed. A new CEO takes over a struggling company. Performance naturally regresses upward, and the CEO gets credit for a "turnaround." Magazine cover athletes have famously bad follow-up seasons — not because of a "curse," but because they made the cover by performing above their mean.\n\nWhenever you see an extreme result followed by a more moderate one, check: is this a real cause-and-effect, or just regression to the mean? Usually, it's the latter.`,
    keyIdea: `Regression to the mean: extreme outcomes are naturally followed by more average ones, not because of any intervention, but because of statistics. We constantly invent causal explanations ("the coach's criticism worked!") for what is simply mathematical reality. Before attributing cause, ask if regression explains the pattern.`,
    quizQuestion: "Why did flight cadets seem to perform better after being criticized?",
    quizOptions: JSON.stringify(["Criticism genuinely motivated them to improve", "Fear of punishment activated better focus", "Their poor performance was below average, so the next attempt naturally regressed toward the mean", "The instructor's feedback contained specific technical corrections"]),
    quizAnswer: 2,
  },
  "card-book-3-10": {
    story: `In the 1960s, the Sydney Opera House was estimated to be completed in 1963 for $7 million. It finally opened in 1973 at a cost of $102 million. The Denver International Airport opened 16 months late at a cost of $4.8 billion — nearly $2 billion over budget. Boston's "Big Dig" highway project was estimated at $2.8 billion and ended up costing over $14.6 billion.\n\nThese aren't exceptions — they're the rule. Kahneman and Tversky called this the planning fallacy: the systematic tendency to underestimate time, costs, and risks while overestimating benefits. It happens to individuals ("I'll finish this paper tonight"), companies ("the project will launch in Q2"), and governments ("the bridge will cost $50 million").\n\nThe root cause is the "inside view" — we focus on the specific details of our plan and construct optimistic scenarios. "If everything goes well, I'll finish by Friday." But how often does everything go well? The corrective is the "outside view": look at how long similar projects have taken in the past. Don't ask "how long will MY kitchen renovation take?" Ask "how long do kitchen renovations usually take?" The answer will be much longer than your optimistic inside-view estimate.\n\nKahneman suggests a specific technique: reference class forecasting. Find 10 similar past projects, look at their actual durations and costs, and use that distribution as your baseline. It's boring, but it's accurate.`,
    keyIdea: `The planning fallacy: we systematically underestimate time, costs, and risks by focusing on our specific plan (the "inside view") instead of looking at how similar projects turned out (the "outside view"). The cure is reference class forecasting — find comparable past projects and use their actual results as your baseline.`,
    quizQuestion: "What is the best way to counter the planning fallacy?",
    quizOptions: JSON.stringify(["Add a 10% buffer to your initial estimate", "Use reference class forecasting — look at how similar past projects actually turned out", "Hire more experienced project managers", "Break the project into smaller tasks and estimate each one"]),
    quizAnswer: 1,
  },
  // ===== PSYCHOLOGY OF MONEY =====
  "card-book-4-1": {
    story: `Bill Gates and Paul Allen were best friends at Lakeside School in Seattle — one of the only high schools in the world with a computer terminal in 1968. The odds of a teenager having access to a computer in the late '60s were about one in a million. Gates himself has said, "If there had been no Lakeside, there would have been no Microsoft."\n\nNow consider Kent Evans. He was a third member of their friend group — equally brilliant, equally driven, equally obsessed with computers. Kent died in a mountaineering accident before he finished high school. Same talent. Same school. Same era. Different luck.\n\nMorgan Housel uses this story to illustrate an uncomfortable truth: luck and risk are two sides of the same coin, and we're terrible at telling them apart. When Bill Gates succeeds, we attribute it to genius and hard work. When someone with equal talent fails, we blame their decisions. But the difference is often just circumstances.\n\nThis doesn't mean effort is irrelevant — it means we should be humbler about success and more compassionate about failure. When judging others' financial outcomes, consider: how much of this was skill, and how much was timing, geography, and fortune? The honest answer is usually "more luck than I'd like to admit."`,
    keyIdea: `Luck and risk are siblings — impossible to separate from skill and effort. Bill Gates' success required both brilliance AND being one of the few teenagers on Earth with computer access in 1968. Be humble about your successes (luck helped) and compassionate about others' failures (risk hurt them).`,
    quizQuestion: "What point does the story of Bill Gates and Kent Evans illustrate?",
    quizOptions: JSON.stringify(["Hard work always leads to success", "Computer access was common in the 1960s", "Success and failure are heavily influenced by luck and risk beyond individual control", "Only students at elite schools can become successful"]),
    quizAnswer: 2,
  },
  "card-book-4-2": {
    story: `Rajat Gupta had it all. Born in poverty in Kolkata, orphaned as a teenager, he rose to become CEO of McKinsey — one of the most prestigious positions in the business world. His net worth was estimated at $100 million. He sat on the boards of Goldman Sachs, Procter & Gamble, and the Bill & Melinda Gates Foundation.\n\nBut $100 million wasn't enough. Gupta wanted to be a billionaire. He wanted to be in the same room as the ultra-wealthy, not just advising them. So he began passing insider information to hedge fund manager Raj Rajaratnam. The trades made him a few million dollars — a rounding error on his existing wealth. In 2012, he was convicted of insider trading and sentenced to prison.\n\nHe risked everything he had and didn't need for something he didn't have and didn't need. This is the "never enough" problem. Modern capitalism is brilliant at two things: generating wealth and generating envy. Social comparison moves the goalpost perpetually. Make a million? Your neighbor has ten million. Make ten? The guy on the magazine has a billion.\n\nWarren Buffett's partner Charlie Munger once said at a party full of billionaires: "Some of these guys would trade their entire fortune to have what you and I have — enough." Knowing when you have enough isn't about limiting ambition. It's about recognizing that the downside of reaching for more can be catastrophic.`,
    keyIdea: `The hardest financial skill is knowing when you have enough. Social comparison moves the goalpost endlessly. Rajat Gupta risked $100 million and his freedom for marginal gains he didn't need. The real danger isn't failing to get more — it's destroying what you already have by reaching too far.`,
    quizQuestion: "What was Rajat Gupta's fundamental financial mistake?",
    quizOptions: JSON.stringify(["He didn't diversify his investments", "He risked everything he had for gains he didn't need", "He invested too heavily in technology stocks", "He failed to hire good financial advisors"]),
    quizAnswer: 1,
  },
  "card-book-4-3": {
    story: `Warren Buffett's net worth is roughly $85 billion. He's considered the greatest investor of all time. But here's a number that doesn't get enough attention: $84.2 billion of that was earned after his 50th birthday. And $81.5 billion came after his 65th birthday.\n\nBuffett started investing when he was 10 years old. By 30, he had a net worth of $1 million (about $9.3 million in today's dollars). He was already an exceptional investor. But the vast majority of his wealth came not from being an exceptional investor, but from being an investor for 75 years.\n\nImagine an alternative universe where Buffett started investing at 30, earned the same phenomenal returns, and retired at 60. His net worth would be about $11.9 million — 99.9% less than his actual fortune. Not because of less skill, but less time.\n\nCompounding is not intuitive. Our brains think linearly: if something grows 10% per year, we mentally multiply. But compounding is exponential, and exponential growth feels like nothing for a long time and then feels like everything all at once. An ice cube sitting in the sun barely changes... barely changes... barely changes... then suddenly it's a puddle. This is why starting early matters more than investing brilliantly.`,
    keyIdea: `Buffett's fortune isn't mainly about investing skill — it's about 75 years of compounding. $81.5 billion of his $85 billion came after age 65. Compounding is not intuitive; it rewards patience above all else. Starting early and staying consistent matters more than finding the perfect investment.`,
    quizQuestion: "What is the primary reason for Warren Buffett's enormous wealth?",
    quizOptions: JSON.stringify(["He consistently achieved the highest returns in history", "He inherited a large fortune and grew it", "He started investing extremely young and let compounding work for 75 years", "He took massive risks on a few key investments"]),
    quizAnswer: 2,
  },
  "card-book-4-4": {
    story: `Imagine you see someone driving a $150,000 Porsche. What do you think? Most people think: "That person is rich. I'd like to be rich too. I should get a nice car." But Housel argues you're making a logical error.\n\nWhen you see someone driving a luxury car, you almost never think about the driver. You think about yourself — "people would think I'm cool/successful/important if I had that car." Ironically, when you do buy the car, other people won't think about you either. They'll think about themselves in the car.\n\nBut the deeper insight is this: the person driving the Porsche might not even be wealthy. They might have $150,000 less in wealth than they had before buying it. They might be making payments on it. The car tells you nothing about their net worth — only about their spending.\n\nWealth is invisible. It's the money not spent. It's the retirement account you never show off, the emergency fund nobody sees, the investments quietly compounding. The flashy car, the big house, the designer clothes — those are the absence of wealth. They're wealth that was converted into stuff. True wealth is the option to buy things you choose not to buy. It's financial freedom, not financial display.`,
    keyIdea: `Wealth is what you don't see — money not spent, not displayed. When you see luxury items, you're seeing the absence of wealth, not its presence. True wealth is invisible: it's financial assets that provide options and freedom. Don't confuse spending with having.`,
    quizQuestion: "According to Housel, what does a luxury car actually tell you about its owner?",
    quizOptions: JSON.stringify(["They are definitely wealthy", "They have good taste and success", "Very little — it only shows spending, not actual wealth", "They are financially irresponsible"]),
    quizAnswer: 2,
  },
  "card-book-4-5": {
    story: `In the 1940s, a young economist named Franklin Templeton started buying stocks during World War II — when most investors were terrified. He bought $100 worth of every stock trading below $1 on the New York Stock Exchange. Many were on the brink of bankruptcy. Several went to zero. But the ones that survived made him a fortune.\n\nWhat did he know that others didn't? He didn't have insider information or a genius thesis. He simply understood that saving creates options. By having money saved and available, he could act when the opportunity arrived — when everyone else was paralyzed by fear.\n\nMorgan Housel argues that saving doesn't need a purpose. The traditional advice says "save for a house" or "save for retirement." But the most valuable aspect of saving is the flexibility it provides for situations you can't predict. You can't anticipate a layoff, a health crisis, an incredible business opportunity, or a once-in-a-generation market crash. But savings let you respond to all of them.\n\nSaving is the gap between your ego and your income. You don't need to earn more to save more — you need to want less. And in a world where your biggest expense is often keeping up with the spending of people you're trying to impress, wanting less is the most powerful financial skill of all.`,
    keyIdea: `Save without a specific reason. The real value of savings isn't funding a purchase — it's providing flexibility and control over your future. Savings let you act on unexpected opportunities and survive unexpected crises. Saving is the gap between your ego and your income.`,
    quizQuestion: "What is the most valuable aspect of saving money, according to Housel?",
    quizOptions: JSON.stringify(["Earning interest and investment returns", "Having enough for a specific purchase like a house", "The flexibility to handle unpredictable future events", "Impressing others with your financial discipline"]),
    quizAnswer: 2,
  },
  "card-book-4-6": {
    story: `During the 2008 financial crisis, two types of investors emerged. The first group had perfectly optimized portfolios: maximum stock exposure, leveraged positions, and mathematically "rational" asset allocations. When markets dropped 50%, many of these investors panicked, sold at the bottom, and locked in devastating losses. They couldn't sleep. Some had heart attacks.\n\nThe second group had "suboptimal" portfolios by any textbook measure: more bonds than their age warranted, some cash sitting idle, maybe even a CD earning 2%. When markets crashed, they were concerned but not terrified. They slept fine. Some even bought stocks at bargain prices. By 2013, many had recovered and then some.\n\nWhich group was smarter? Housel argues it was the second group. Not because their strategy was mathematically superior, but because they could actually stick with it. A perfectly rational portfolio that causes you to panic-sell is worse than a "suboptimal" one you can maintain through thick and thin.\n\nThis is the "reasonable vs. rational" principle. Rational decisions maximize expected value on paper. Reasonable decisions account for the fact that you're a human being with emotions, fears, and a need for sleep. The best financial plan is the one you can follow — not the one that looks best in a spreadsheet.`,
    keyIdea: `Aim to be reasonable, not rational. A mathematically "optimal" plan that causes you to panic during downturns is worse than a conservative plan you can stick with. The best financial strategy is one that lets you sleep at night — because the biggest risk is abandoning your plan entirely.`,
    quizQuestion: "Why does Housel argue that 'reasonable' beats 'rational' in finance?",
    quizOptions: JSON.stringify(["Rational strategies are always too risky", "Reasonable strategies have higher mathematical returns", "A strategy you can emotionally stick with outperforms one that causes panic-selling", "Financial models are always inaccurate"]),
    quizAnswer: 2,
  },
  "card-book-4-7": {
    story: `Heinz Berggruen fled Nazi Germany in 1936, became an art dealer, and assembled one of the most valuable private art collections in history. His collection, eventually sold to the German government for over €100 million, included works by Picasso, Klee, Matisse, and Giacometti.\n\nBut here's what most people don't know: for every masterpiece Berggruen acquired, he bought dozens — maybe hundreds — of pieces that turned out to be unremarkable. His success wasn't about being right every time. It was about being in the game long enough for a few spectacular wins to compensate for many mediocre outcomes.\n\nThis is how tails work. In investing, in business, in art, in venture capital — a tiny number of events produce the vast majority of results. Amazon's stock has had many down years, but a handful of extraordinary years account for virtually all of its returns. A venture capital fund might invest in 50 companies; one or two become Google, and the rest fail. The fund still makes a fortune.\n\nThe implication is liberating: you can be wrong a lot and still do well, as long as your winners are big enough. The key is staying in the game. Don't let a few losses convince you to quit. The tail event — the one that changes everything — might be just around the corner.`,
    keyIdea: `A small number of events drive the majority of outcomes in investing, business, and life. You can be wrong most of the time and still succeed spectacularly if your winners are big enough. The key is staying in the game long enough for the tail events to find you.`,
    quizQuestion: "What is the key lesson from Heinz Berggruen's art collecting strategy?",
    quizOptions: JSON.stringify(["Only buy art from famous artists", "Every purchase should be carefully evaluated to ensure it's a masterpiece", "A few spectacular wins can compensate for many mediocre outcomes", "Art collecting requires insider knowledge of the market"]),
    quizAnswer: 2,
  },
  "card-book-4-8": {
    story: `In 2008, a Las Vegas real estate investor named Bob had a $4 million portfolio of rental properties generating $400,000 per year in income. On paper, he was wealthy. Then the financial crisis hit. Property values dropped 60%. Two of his tenants stopped paying rent. One building needed emergency repairs. His mortgage payments stayed the same.\n\nBob hadn't done anything wrong. His properties were in good locations, his tenants had been reliable, his returns were solid. But his plan had no room for error. Every dollar of income was allocated. Every property was leveraged. When the improbable happened, he had no buffer. He lost everything.\n\nContrast this with an investor who bought fewer properties, with larger down payments and a year's worth of expenses in cash. Her returns were lower in good years. But when the crisis hit, she survived. She even bought Bob's properties at a discount.\n\nHousel calls this "room for error" — and it's the most important part of any financial plan. The world runs on probabilities, not certainties. The thing that kills you is always the thing you didn't see coming. A margin of safety isn't just for pessimists; it's for anyone who acknowledges that the future is unknown. Plan for your plan not going according to plan.`,
    keyIdea: `The most important part of every plan is planning on your plan not going according to plan. Room for error — cash reserves, conservative leverage, flexible timelines — is what lets you survive the inevitable surprises. Optimizing for the best case leaves you vulnerable to the worst.`,
    quizQuestion: "What was the fundamental flaw in Bob's real estate investment strategy?",
    quizOptions: JSON.stringify(["He invested in poor locations", "He had no margin of safety — every dollar was allocated and leveraged", "He didn't diversify across different cities", "He bought at the peak of the market"]),
    quizAnswer: 1,
  },
  "card-book-4-9": {
    story: `A young woman who grew up in extreme poverty, where every dollar was a life-or-death decision, might naturally hoard cash and distrust banks. A baby boomer who grew up during the post-war boom, where stocks seemed to only go up, might pour everything into equities. A millennial who graduated into the 2008 recession might be permanently risk-averse about housing.\n\nAre any of these people "crazy"? Morgan Housel says no — they're all perfectly rational given their experiences. The problem is that your personal experience with money represents a vanishingly small slice of how the world actually works, yet it accounts for maybe 80% of how you think the world works.\n\nA study by economists Ulrike Malmendier and Stefan Nagel found that your investing behavior is heavily influenced by the returns the stock market earned during your formative years (roughly ages 18-35). People who experienced high returns during that period invest more aggressively for the rest of their lives. Those who lived through crashes stay conservative forever.\n\nThis means everyone is playing a different financial game, shaped by different experiences, in the same market. The person who seems to be making "crazy" financial decisions might just be responding rationally to a different lived history than yours. Understanding this breeds empathy — and better self-awareness about your own biases.`,
    keyIdea: `No one is "crazy" about money — everyone's financial behavior is shaped by their unique life experiences. What seems irrational from the outside makes perfect sense given someone's personal history. Your experience is a tiny fraction of reality but dominates your worldview. Respect that everyone is playing a different game.`,
    quizQuestion: "According to research, what most influences a person's investment behavior?",
    quizOptions: JSON.stringify(["Their formal financial education", "The stock market returns during their formative years (ages 18-35)", "Advice from financial advisors", "Their current income level"]),
    quizAnswer: 1,
  },
  "card-book-4-10": {
    story: `In 1945, a man named Ronald Read worked as a gas station attendant and janitor in rural Vermont. He fixed his own car, wore secondhand clothes, and chopped his own firewood. When he died in 2014 at age 92, his neighbors were shocked to learn he'd left behind a fortune of $8 million — most of which he donated to the local hospital and library.\n\nRead's "strategy" wasn't complex. He invested in blue-chip dividend stocks and never sold. For decades. That's it. No hedge fund access, no MBA, no financial advisor. Just patience, frugality, and time.\n\nMorgan Housel uses Read's story to illustrate the highest form of wealth: the freedom to do whatever you want with your time. Read didn't want luxury. He wanted to wake up each morning and decide for himself how to spend his day — tending his garden, visiting the library, sitting on his porch.\n\nResearch consistently shows that the single most reliable predictor of positive well-being isn't income, status, or possessions — it's the feeling of controlling your own time. A janitor who controls his schedule is often happier than a CEO who doesn't. Money's greatest intrinsic value — its true superpower — is giving you options and autonomy over what you do, when you do it, and with whom.`,
    keyIdea: `The highest dividend money pays is control over your time. Research shows that autonomy — the ability to do what you want, when you want, with whom you want — is the strongest predictor of happiness. A janitor who controls his schedule may be happier than a CEO who doesn't. Use money to buy freedom, not stuff.`,
    quizQuestion: "What made Ronald Read's financial strategy so successful?",
    quizOptions: JSON.stringify(["He had access to exclusive investment opportunities", "He used complex trading algorithms", "He invested patiently in blue-chip stocks for decades and never sold", "He received a secret inheritance early in life"]),
    quizAnswer: 2,
  },
  // ===== SAPIENS =====
  "card-book-5-1": {
    story: `Seventy thousand years ago, Homo sapiens was just one of several human species roaming the Earth. Neanderthals dominated Europe. Homo erectus held Southeast Asia. We were confined to a small corner of Africa, unremarkable in the grand scheme of things. Then something changed.\n\nArchaeologists call it the Cognitive Revolution — a mysterious leap in human capabilities that occurred between 70,000 and 30,000 years ago. Suddenly, Sapiens began creating art, developing sophisticated tools, and spreading across the globe at an unprecedented rate. Within a few thousand years, every other human species was extinct.\n\nWhat happened? Yuval Noah Harari argues it was a mutation in our brain's wiring that gave us a unique form of language. Not just any language — many animals communicate. Our language could do something no other could: describe things that don't exist. We could talk about gods, spirits, nations, human rights, and limited liability corporations. We could tell stories.\n\nThis ability to create and believe in shared fictions is what allowed Sapiens to cooperate in massive numbers. A chimpanzee band maxes out around 50 members. A human tribe, bound by a shared myth, can coordinate millions. The Cognitive Revolution didn't give us better claws or faster legs. It gave us stories — and stories conquered the world.`,
    keyIdea: `The Cognitive Revolution (~70,000 years ago) gave Homo sapiens a unique superpower: the ability to create and believe in shared fictions. Language about imaginary things — gods, nations, money, laws — enables massive cooperation among strangers. Stories, not strength, made us the dominant species.`,
    quizQuestion: "What made Homo sapiens' language unique compared to other animals' communication?",
    quizOptions: JSON.stringify(["It was louder and could travel further distances", "It could describe things that don't physically exist — myths, gods, and abstract concepts", "It used more complex grammar and vocabulary", "It was the first form of written communication"]),
    quizAnswer: 1,
  },
  "card-book-5-2": {
    story: `In 2011, a revolution in Egypt toppled President Mubarak. Millions of strangers — who had never met, would never meet — coordinated their actions around shared beliefs: "freedom," "democracy," "justice." These concepts don't exist in any physical sense. You can't touch democracy. You can't smell justice. Yet people died for them.\n\nThis is the power of fiction, and it's the single most important insight in Sapiens. Every large-scale human institution is built on stories we collectively agree to believe. Take money: a $100 bill is a piece of paper. It has value only because millions of people share the fiction that it does. If everyone stopped believing in dollars tomorrow, they'd be worth nothing.\n\nCorporations are legal fictions — Peugeot exists not as a physical thing but as a shared story backed by laws (themselves fictions) and courts (institutions maintained by shared belief). Nations are fictions: there's no physical border between France and Germany, only an agreed-upon line on a map. Human rights are fictions — beautiful, powerful fictions that exist nowhere in nature.\n\nHarari isn't saying these things are "lies" or "bad." He's saying they're imagined realities — and imagined realities are the most powerful force in history. Every war was fought, every cathedral built, every law written because humans believed in a shared story. The ability to create fiction isn't a bug in human cognition. It's our greatest feature.`,
    keyIdea: `Every large-scale human cooperation — money, nations, corporations, religion, human rights — is rooted in shared fiction. These aren't lies; they're "imagined realities" that enable millions of strangers to work together. The power of fiction is humanity's greatest and most distinctive ability.`,
    quizQuestion: "According to Harari, what makes large-scale human cooperation possible?",
    quizOptions: JSON.stringify(["Genetic similarity between humans", "Shared belief in imagined realities like money, nations, and laws", "Fear of punishment by authorities", "Natural instinct for group behavior inherited from primates"]),
    quizAnswer: 1,
  },
  "card-book-5-3": {
    story: `About 10,000 years ago, humans made what seemed like a clever decision: instead of wandering around gathering wild wheat, why not plant it deliberately? Instead of chasing wild goats, why not keep them in a pen? This was the Agricultural Revolution, and Harari argues it was "history's biggest fraud."\n\nConsider what happened. Foragers worked about 4-6 hours per day, ate a varied diet of dozens of different foods, and rarely experienced famine (they could move to where food was). Farmers worked sunrise to sunset, ate a monotonous diet (mostly wheat or rice), and were devastated by droughts and crop failures. Their bones show more disease, more malnutrition, and more wear.\n\nSo why didn't they go back? Because agriculture created a population trap. Farming produced more calories per acre, which meant more babies survived, which meant more mouths to feed, which required more farming. Within a few generations, the knowledge of foraging was lost, and there were too many people to sustain without agriculture. The trap was sprung.\n\nHarari puts it provocatively: wheat didn't serve us — we served wheat. We cleared its forests, we carried its water, we removed its competitors, we spread it across the globe. From wheat's perspective, Homo sapiens is the best thing that ever happened. From an individual human's perspective? The Agricultural Revolution traded quality of life for quantity of life.`,
    keyIdea: `The Agricultural Revolution wasn't progress — it was a trap. Farming produced more food but worse lives: harder work, worse diet, more disease. Population growth made it impossible to return to foraging. Harari provocatively argues that wheat domesticated humans, not the other way around.`,
    quizQuestion: "Why couldn't early farmers return to a foraging lifestyle?",
    quizOptions: JSON.stringify(["Laws prohibited abandoning farmland", "Population had grown too large to sustain without agriculture", "Foraging skills were considered primitive and shameful", "Wild food sources had been completely exhausted"]),
    quizAnswer: 1,
  },
  "card-book-5-4": {
    story: `You wake up, check your phone (believing in the authority of the time displayed), get dressed (wearing clothes that signal your social status — an imagined hierarchy), drive to work (following traffic laws — imagined rules), and arrive at your office (owned by a corporation — an imagined entity). You work to earn money (an imagined value system) to buy a house (whose ownership is defined by imagined property rights).\n\nEvery moment of your day is structured by imagined orders — systems of belief so deeply embedded that they feel as natural as gravity. But gravity would exist even if nobody believed in it. Property rights would not.\n\nHarari points out that imagined orders are not "conspiracies" or "illusions." They're inter-subjective realities: things that exist because millions of people collectively believe in them. They shape not just our societies but our deepest desires. You want a vacation in Paris? That desire was shaped by Romantic myths about travel and European culture. You want a big lawn? That was shaped by aristocratic ideals filtered through suburban development marketing.\n\nThe most radical implication: even our sense of "individuality" is shaped by imagined orders. The modern belief that every person has unique inner worth, individual rights, and personal freedom — that itself is a story. A powerful, useful story. But a story nonetheless.`,
    keyIdea: `Imagined orders — laws, social hierarchies, property rights — structure every moment of our lives and even shape our desires. They feel natural but would vanish if people stopped believing in them. Even our cherished individualism is an imagined order, not a natural fact. Understanding this is both unsettling and liberating.`,
    quizQuestion: "What makes imagined orders so powerful, according to Harari?",
    quizOptions: JSON.stringify(["They are enforced by military power alone", "They are embedded so deeply in our culture that they feel as natural as physical laws", "They are written into human DNA through evolution", "They are only followed by uneducated populations"]),
    quizAnswer: 1,
  },
  "card-book-5-5": {
    story: `In 1519, Hernán Cortés landed in Mexico with 500 soldiers and wanted to buy provisions from the local people. He offered them gold coins. The locals looked at them blankly. Gold meant nothing to them — they used cacao beans and cloth as currency. Yet within a generation, the same population would fight and die for gold, because the Spanish imagined order had been imposed.\n\nMoney is the most successful story ever told. It's the only system of mutual trust that can bridge almost any cultural gap. Christians and Muslims who disagree on everything else will happily trade using the same currency. Warring nations maintain financial relationships even during conflicts.\n\nWhat makes money work isn't its material. Cowrie shells, silver coins, paper notes, digital numbers — the medium changes constantly. What stays constant is trust. Money is anything that people are willing to use to represent the value of other things, for the purpose of exchanging goods and services.\n\nThe genius of money is that it converts everything into a common denominator. A soldier's courage, a priest's blessing, a farmer's wheat — all become comparable and exchangeable. But this creates a dark side too: things that shouldn't be for sale (loyalty, love, justice) get price tags attached. Money doesn't just facilitate trade; it reshapes what we value.`,
    keyIdea: `Money is the most universal system of mutual trust ever invented — the only story that nearly all humans believe simultaneously. Its power comes not from its material form but from shared trust. Money converts everything into a common language of value, bridging cultures and enabling cooperation on a global scale.`,
    quizQuestion: "What gives money its value, according to Harari?",
    quizOptions: JSON.stringify(["The precious metals it's made from", "Government declarations and laws", "Collective trust and shared belief in its value", "The amount of labor required to produce it"]),
    quizAnswer: 2,
  },
  "card-book-5-6": {
    story: `In 221 BC, the kingdom of Qin conquered all other Chinese states and unified them into the first Chinese Empire. For the local populations, it was a catastrophe — war, deportation, forced labor. But over centuries, something remarkable happened. Former enemies began to see themselves as "Chinese." Their languages merged, their customs blended, their identities fused. Today, over a billion people identify as Chinese — a identity that was forged by imperial conquest.\n\nThis pattern repeats throughout history. The Roman Empire conquered dozens of distinct peoples — Gauls, Iberians, Greeks, Egyptians. Within a few centuries, they were all "Roman." The British Empire did the same: the world's most widely spoken language, most popular sport (soccer), and dominant legal traditions are all imperial legacies.\n\nHarari observes an uncomfortable trend: history moves toward unity. Empire after empire has absorbed diverse peoples into larger cultural units. Today's "authentic" cultures are usually yesterday's imperial impositions. Indians speak English. Mexicans follow a Spanish religion. The whole world uses Arabic numerals.\n\nThe direction of history isn't toward fragmentation — it's toward global unification. We already have a global economy, global science, and increasingly global culture. Whether this leads to a single world empire or something entirely new remains the biggest open question of our species' future.`,
    keyIdea: `History shows a clear trend toward larger cultural and political units through imperial cycles. Today's "authentic" cultures are often yesterday's imperial impositions. History moves toward unity, not fragmentation — and we're already in a globally interconnected civilization with shared economics, science, and culture.`,
    quizQuestion: "What long-term pattern does Harari identify in human political history?",
    quizOptions: JSON.stringify(["Cultures naturally fragment into smaller, more distinct groups over time", "History moves toward larger units of cooperation and cultural unification through empires", "Democracies have always been the dominant form of government", "Political structures remain constant across centuries"]),
    quizAnswer: 1,
  },
  "card-book-5-7": {
    story: `For most of human history, the world's most powerful civilization was China. Chinese technology, culture, and economy dominated Asia for millennia. The Muslim world was the center of science and philosophy during Europe's Dark Ages. So why did a relatively backward peninsula on the western edge of Eurasia end up conquering the world?\n\nHarari's answer is surprising: ignorance. Specifically, the European willingness to admit it. In 1492, when Columbus set sail, he didn't know what he'd find. That admission of ignorance — "there's something out there we don't know about" — was revolutionary. Chinese and Muslim empires, confident in their existing knowledge, saw little reason to explore.\n\nThe Scientific Revolution that began in Europe around 1500 was built on a radical premise: we don't know everything, and through observation and experiment, we can learn. This seems obvious now, but it was a stunning cultural shift. Most previous civilizations assumed that all important knowledge already existed — in religious texts, ancient traditions, or the teachings of sages.\n\nThe marriage of science and empire was the key. European empires funded exploration and research not out of pure curiosity, but because knowledge meant power. Botany helped colonize new lands. Cartography enabled navigation. Linguistics enabled control of foreign populations. Science and conquest fueled each other in a spiral that transformed the planet.`,
    keyIdea: `The Scientific Revolution succeeded in Europe because Europeans uniquely admitted their own ignorance. The willingness to say "I don't know" and investigate was revolutionary — most civilizations assumed important knowledge was already known. The marriage of science and empire created a feedback loop of discovery and conquest that reshaped the world.`,
    quizQuestion: "What cultural trait gave Europeans an advantage in the Scientific Revolution?",
    quizOptions: JSON.stringify(["Superior intelligence compared to other civilizations", "The willingness to admit ignorance and seek new knowledge through experimentation", "A longer tradition of formal education", "Access to more natural resources than other regions"]),
    quizAnswer: 1,
  },
  "card-book-5-8": {
    story: `In 1831, a young Charles Darwin set sail on the Beagle, leaving behind a life of relative comfort in England. He'd spend five years traveling the world, getting seasick, collecting beetles, and observing finches on the Galápagos Islands. When he returned, he spent another 20 years refining his theory before publishing "On the Origin of Species."\n\nDarwin's theory tells us that evolution has no purpose, no direction, no goal. It simply selects for whatever survives and reproduces. Happy or miserable, it doesn't matter — as long as you pass on your genes.\n\nHarari uses this to ask a provocative question: did the Agricultural Revolution, the Industrial Revolution, and all our "progress" actually make humans happier? The evidence is unsettling. Studies of contemporary hunter-gatherer societies show they often have more leisure time, stronger social bonds, and lower rates of depression than modern workers.\n\nBiochemically, happiness is determined by your brain's baseline of serotonin, dopamine, and oxytocin — set largely by genetics, not circumstances. A medieval peasant and a modern billionaire might have similar happiness levels if their brain chemistry is similar. We've built skyscrapers and sent rockets to the moon, but our capacity for happiness is still running on Stone Age hardware.`,
    keyIdea: `Progress doesn't guarantee happiness. Our brain's happiness "set point" is largely biochemical and genetic, not determined by external circumstances. A medieval peasant might have been as happy as a modern executive. The real question of history isn't "what did we build?" but "did it make us feel better?"`,
    quizQuestion: "According to Harari, what primarily determines an individual's happiness level?",
    quizOptions: JSON.stringify(["Their wealth and material possessions", "The era and society they live in", "Their biochemical brain settings (serotonin, dopamine, oxytocin levels)", "Their education level and career success"]),
    quizAnswer: 2,
  },
  "card-book-5-9": {
    story: `On a factory farm in Iowa, a sow spends her entire life in a gestation crate — a metal cage so small she can't turn around. She will be artificially inseminated, give birth, have her piglets taken away, and be inseminated again. This cycle repeats until her body gives out, typically after 3-4 years (her natural lifespan would be 15-20 years).\n\nShe is, by any objective measure, one of the most intelligent animals on the farm — smarter than most dogs, capable of complex emotions, problem-solving, and social relationships. Neuroscience confirms that pigs experience pain, distress, boredom, and fear in ways remarkably similar to humans.\n\nHarari argues that the domestication of animals may be the greatest crime in history. The Agricultural Revolution didn't just trap humans — it subjected billions of animals to lives of unimaginable suffering. Today, roughly 70 billion land animals are slaughtered for food each year, most having lived in industrial conditions that deny every natural instinct.\n\nThe numbers are staggering. There are about 1.5 billion cattle, 1 billion pigs, and 25 billion chickens alive at any given time — all bred for human use. From the perspective of evolutionary "success" (total biomass), domesticated animals are winners. From the perspective of individual experience, they are among the most miserable creatures ever to exist.`,
    keyIdea: `The agricultural and industrial revolutions turned animals from partners in an ecosystem into industrial units of production. Billions of sentient beings live in conditions of extreme suffering. Harari calls this potentially the greatest crime in history — a moral blind spot that future generations may judge as harshly as we judge slavery.`,
    quizQuestion: "How does Harari frame the domestication of animals in human history?",
    quizOptions: JSON.stringify(["As a necessary step for human civilization that benefited both species", "As potentially the greatest crime in history due to the scale of animal suffering", "As irrelevant to the broader narrative of human progress", "As an arrangement that improved animals' survival rates"]),
    quizAnswer: 1,
  },
  "card-book-5-10": {
    story: `In 2010, Craig Venter and his team created the first synthetic life form — a bacterium with a genome designed entirely on a computer. For 4 billion years, life on Earth evolved through natural selection. In a single laboratory breakthrough, that changed.\n\nHarari argues we are at the threshold of the most important revolution in the history of life — not just human history. For the first time, a species has the ability to design life itself. CRISPR gene editing, brain-computer interfaces, artificial intelligence, and nanotechnology are giving us godlike powers that our Stone Age brains may not be equipped to handle.\n\nConsider what's already happening: we can select embryos for specific genetic traits, grow organs in labs, connect brains to computers, and create AI that outperforms humans at an expanding list of tasks. The next century may see the emergence of entirely new life forms — cyborgs, genetically enhanced humans, or digital minds.\n\nThe three existential challenges of the 21st century, Harari suggests, aren't war, famine, or plague (we've largely conquered those). They're the same three things that used to be prayers: overcoming death, finding perpetual happiness, and upgrading humans to gods. We're no longer praying for these things — we're engineering them. Whether that makes us Homo Deus or Homo Destructus remains to be seen.`,
    keyIdea: `For the first time in 4 billion years, life is being shaped by intelligent design rather than natural selection. We're engineering solutions to death, unhappiness, and human limitations. The question isn't whether we'll gain godlike powers — it's whether we'll use them wisely. We may be the last generation of Homo sapiens as we know ourselves.`,
    quizQuestion: "What does Harari mean by 'Homo Deus'?",
    quizOptions: JSON.stringify(["A new species discovered in archaeological sites", "Humans acquiring godlike powers through technology to overcome death and redesign life", "A religious movement in modern society", "The Latin name for modern humans"]),
    quizAnswer: 1,
  },
};

async function seedStories() {
  const allCards = await db.select().from(cards);
  console.log(`Found ${allCards.length} cards to update`);

  let updated = 0;
  for (const card of allCards) {
    const data = storiesByCardId[card.id];
    if (!data) {
      console.warn(`No story data for card ${card.id} (${card.title})`);
      continue;
    }
    await db.update(cards).set({
      story: data.story,
      keyIdea: data.keyIdea,
      quizQuestion: data.quizQuestion,
      quizOptions: data.quizOptions,
      quizAnswer: data.quizAnswer,
    }).where(eq(cards.id, card.id));
    updated++;
  }
  console.log(`Updated ${updated} cards with story content`);
  process.exit(0);
}

seedStories().catch((e) => { console.error(e); process.exit(1); });
